#include<bits/stdc++.h>
using namespace std;
long long b[100010];
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long sum;
        long long tag;
        node():tag(0){}
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    }
    void pushdown(long long x)
    {
        long long l=a[x].l,r=a[x].r,ls=a[x].lson,rs=a[x].rson;
        long long mid=(l+r)>>1,tg=a[x].tag;
        a[ls].sum+=(mid-l+1)*tg;
        a[rs].sum+=(r-mid)*tg;
        a[ls].tag+=tg;
        a[rs].tag+=tg;
        a[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0;
        if(l==r)
        {
            a[x].sum=b[l];
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long v)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].tag+=v;
            a[x].sum+=(a[x].r-a[x].l+1)*v;
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,v);
        add(a[x].rson,l,r,v);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r);
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    while(m--)
    {
        long long op,x,y,k;
        scanf("%lld%lld%lld",&op,&x,&y);
        if(op==1)
        {
            scanf("%lld",&k);
            t.add(1,x,y,k);
        }
        else
        {
            printf("%lld\n",t.getsum(1,x,y));
        }
    }
    return 0;
}
